fun eggDrop(arr: IntArray): Int {
    val eggs = arr[0]; val floors = arr[1]
    val dp = Array(eggs + 1) { IntArray(floors + 1) }
    for (f in 1..floors) dp[1][f] = f
    for (e in 2..eggs) {
        for (f in 1..floors) {
            dp[e][f] = Int.MAX_VALUE
            for (x in 1..f) {
                val worst = 1 + maxOf(dp[e - 1][x - 1], dp[e][f - x])
                dp[e][f] = minOf(dp[e][f], worst)
            }
        }
    }
    return dp[eggs][floors]
}

def egg_drop(arr: list[int]) -> int:
    eggs, floors = arr[0], arr[1]
    dp = [[0] * (floors + 1) for _ in range(eggs + 1)]
    for f in range(1, floors + 1):
        dp[1][f] = f
    for e in range(2, eggs + 1):
        for f in range(1, floors + 1):
            dp[e][f] = float('inf')
            for x in range(1, f + 1):
                worst = 1 + max(dp[e - 1][x - 1], dp[e][f - x])
                dp[e][f] = min(dp[e][f], worst)
    return dp[eggs][floors]

pub fn egg_drop(arr: &[i32]) -> i32 {
    let eggs = arr[0] as usize;
    let floors = arr[1] as usize;
    let mut dp = vec![vec![0i32; floors + 1]; eggs + 1];
    for f in 1..=floors { dp[1][f] = f as i32; }
    for e in 2..=eggs {
        for f in 1..=floors {
            dp[e][f] = i32::MAX;
            for x in 1..=f {
                let worst = 1 + dp[e - 1][x - 1].max(dp[e][f - x]);
                dp[e][f] = dp[e][f].min(worst);
            }
        }
    }
    dp[eggs][floors]
}

object EggDrop {

