    val dp = Array.ofDim[Int](eggs + 1, floors + 1)
    for (f <- 1 to floors) dp(1)(f) = f
    for (e <- 2 to eggs; f <- 1 to floors) {
      dp(e)(f) = Int.MaxValue
      for (x <- 1 to f) {
        val worst = 1 + math.max(dp(e - 1)(x - 1), dp(e)(f - x))
        dp(e)(f) = math.min(dp(e)(f), worst)
      }
    }
    dp(eggs)(floors)
  }
}

func eggDrop(_ arr: [Int]) -> Int {
    let eggs = arr[0], floors = arr[1]
    var dp = Array(repeating: Array(repeating: 0, count: floors + 1), count: eggs + 1)
    if floors > 0 {
        for f in 1...floors { dp[1][f] = f }
    }
    if eggs >= 2 && floors > 0 {
        for e in 2...eggs {
            for f in 1...floors {
                dp[e][f] = Int.max
                for x in 1...f {
                    let worst = 1 + max(dp[e - 1][x - 1], dp[e][f - x])
                    dp[e][f] = min(dp[e][f], worst)
                }
            }
        }
    }
    return dp[eggs][floors]
}

export function eggDrop(arr: number[]): number {
    const eggs = arr[0], floors = arr[1];
    const dp: number[][] = Array.from({ length: eggs + 1 }, () => new Array(floors + 1).fill(0));
    for (let f = 1; f <= floors; f++) dp[1][f] = f;
    for (let e = 2; e <= eggs; e++) {
        for (let f = 1; f <= floors; f++) {
            dp[e][f] = Infinity;
            for (let x = 1; x <= f; x++) {
                const worst = 1 + Math.max(dp[e - 1][x - 1], dp[e][f - x]);
                dp[e][f] = Math.min(dp[e][f], worst);
            }
        }
    }
    return dp[eggs][floors];
}
